        {
            "Original": "Server implementers are encouraged to review [RFC4941], [RFC7824], and [RFC7707] as to possible considerations for how to generate addresses.",
            "Adjusted": "No change"
        },
        {
            "Original": "A server MUST NOT assign an address that is otherwise reserved for some other purpose.",
            "Adjusted": "No change"
        },
        {
            "Original": "For example, a server MUST NOT assign addresses that use a reserved IPv6 Interface Identifier [RFC5453] [RFC7136] [IANA-RESERVED-IID].",
            "Adjusted": "No change"
        },
        {
            "Original": "See [RFC7969] for a more detailed discussion on how servers determine a client's location on the network.",
            "Adjusted": "No change"
        }
    ]
}

