            "Original": ".",
            "Adjusted": ""
        },
        {
            "Original": ".",
            "Adjusted": ""
        },
        {
            "Original": "+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+ Figure 32: Interface-Id Option Format option-code OPTION_INTERFACE_ID (18).",
            "Adjusted": "Figure 32 shows the Interface-Id Option Format with option-code OPTION_INTERFACE_ID (18)."
        },
        {
            "Original": "option-len Length of interface-id field.",
            "Adjusted": "No change"
        },
        {
            "Original": "interface-id An opaque value of arbitrary length generated by the relay agent to identify one of the relay agent's interfaces.",
            "Adjusted": "No change"
        },
        {
            "Original": "The length, in octets, is specified by option-len.",
