        {
            "Original": ".",
            "Adjusted": "Removed"
        },
        {
            "Original": ".",
            "Adjusted": "Removed"
        },
        {
            "Original": "+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+ Figure 15: Identity Association for Non-temporary Addresses Option Format option-code OPTION_IA_NA (3).",
            "Adjusted": "Figure 15 shows the Identity Association for Non-temporary Addresses Option Format. The option-code is OPTION_IA_NA (3)."
