        },
        {
            "Original": "IAID The unique identifier for this IA_NA; the IAID must be unique among the identifiers for all of this client's IA_NAs.",
            "Adjusted": "IAID is the unique identifier for this IA_NA; the IAID must be unique among the identifiers for all of this client's IA_NAs."
